import { useIntl } from 'react-intl';

import { Suggestion } from './Suggestion.js';
import { SuggestionGroup } from './SuggestionGroup.js';
import { useFilterFieldContext } from '../hooks/useFilterFieldContext.js';
import { filterFieldMessages } from '../messages.js';

/**
 * @internal
 */
export function LogicalOperatorSuggestionsGroup() {
  const { logicalOperatorSuggestionValues } = useFilterFieldContext();
  const intl = useIntl();

  if (logicalOperatorSuggestionValues.length === 0) {
    return null;
  }

  return (
    <SuggestionGroup
      aria-label={intl.formatMessage(
        filterFieldMessages.suggestions.a11y.logicalOperators,
      )}
    >
      {logicalOperatorSuggestionValues.map((suggestion, index) => (
        <Suggestion key={suggestion.value ?? index} {...suggestion} />
      ))}
    </SuggestionGroup>
  );
}
